SELECT

FROM t_erp_biz_abnormal_pool


        AND biz_type = #{bizType}


        AND biz_id = #{bizId}


        AND abnormal_code like concat('%', #{abnormalCode}, '%')


        AND abnormal_title like concat('%', #{abnormalTitle}, '%')


        AND abnormal_level = #{abnormalLevel}


        AND status = #{status}


        AND lock_biz = #{lockBiz}


ORDER BY abnormal_level DESC, create_time ASC

